43. /// <summary>
44. /// Default implementation of <see cref="IFormatter"/> providing English date/time formatting.
45. /// </summary>
46. public sealed class DefaultFormatter : IFormatter
47. {
48.     /// <inheritdoc />
49.     public string DateHumanize_Now() => "now";
50. 
51.     /// <inheritdoc />
52.     public string DateHumanize_Never() => "never";
53. 
54.     /// <inheritdoc />
55.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
56.     {
57.         var unit = GetUnitName(timeUnit, count != 1);
58.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
59.     }
60. 
61.     private static string GetUnitName(TimeUnit timeUnit, bool plural) =>
62.         (timeUnit, plural) switch
63.         {
64.             (TimeUnit.Year, false) => "year",
65.             (TimeUnit.Year, true) => "years",
66.             (TimeUnit.Month, false) => "month",
67.             (TimeUnit.Month, true) => "months",
68.             (TimeUnit.Day, false) => "day",
69.             (TimeUnit.Day, true) => "days",
70.             (TimeUnit.Hour, false) => "hour",
71.             (TimeUnit.Hour, true) => "hours",
72.             (TimeUnit.Minute, false) => "minute",
73.             (TimeUnit.Minute, true) => "minutes",
74.             (TimeUnit.Second, false) => "second",
75.             (TimeUnit.Second, true) => "seconds",
76.             _ => plural ? timeUnit.ToString().ToLowerInvariant() + "s"
77.                         : timeUnit.ToString().ToLowerInvariant()
78.         };
79. 
80.     private static string NumberToWords(int number) =>
81.         number switch
82.         {
83.             1 => "one",
84.             2 => "two",
85.             3 => "three",
86.             _ => number.ToString()
87.         };
88. }
