163. /// <summary>
164. /// Default ordinalizer providing English ordinal suffixes (1st, 2nd, 3rd, etc.).
165. /// </summary>
166. // Base class — intentionally unsealed so locale-specific ordinalizers can inherit.
167. public class DefaultOrdinalizer : IOrdinalizer
168. {
169.     /// <inheritdoc />
170.     public virtual string Convert(int number, string numberString)
171.     {
172.         var suffix = (number % 100) switch
173.         {
174.             11 or 12 or 13 => "th",
175.             _ => (number % 10) switch
176.             {
177.                 1 => "st",
178.                 2 => "nd",
179.                 3 => "rd",
180.                 _ => "th"
181.             }
182.         };
183. 
184.         return numberString + suffix;
185.     }
186. }
