241. /// <summary>
242. /// Registry for locale-specific formatters, ordinalizers, and converters.
243. /// Provides thread-safe registration and lookup of locale implementations.
244. /// </summary>
245. public sealed class LocaleRegistry
246. {
247.     private readonly ConcurrentDictionary<string, IFormatter> _formatters = new(StringComparer.OrdinalIgnoreCase);
248.     private readonly ConcurrentDictionary<string, IOrdinalizer> _ordinalizers = new(StringComparer.OrdinalIgnoreCase);
249.     private readonly IFormatter _defaultFormatter = new DefaultFormatter();
