293. /// <summary>
294. /// Strategies for humanizing date/time differences.
295. /// </summary>
296. public sealed class DefaultDateTimeHumanizeStrategy
297. {
298.     /// <summary>
299.     /// Humanizes a DateTime difference relative to a base date.
300.     /// </summary>
301.     /// <param name="input">The date to humanize.</param>
302.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
303.     /// <returns>A human-readable string representing the time difference.</returns>
304.     public string Humanize(DateTime input, DateTime comparedTo)
305.     {
306.         var difference = comparedTo - input;
307.         if (Math.Abs(difference.TotalSeconds) < 2)
308.         {
309.             return "just now";
310.         }
311. 
312.         var isFuture = difference.TotalSeconds < 0;
313.         var absDiff = difference.Duration();
314. 
315.         var result = absDiff.TotalDays switch
316.         {
317.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
318.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
319.             >= 1 => $"{(int)absDiff.TotalDays} days",
320.             _ => absDiff.TotalHours switch
321.             {
322.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
323.                 _ => absDiff.TotalMinutes switch
324.                 {
325.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
326.                     _ => $"{(int)absDiff.TotalSeconds} seconds"
327.                 }
328.             }
329.         };
330. 
331.         return isFuture ? $"in {result}" : $"{result} ago";
332.     }
333. }
