344.     /// <param name="toSymbol">Whether to return the symbol instead of the full name.</param>
345.     /// <returns>The display name or symbol for the unit.</returns>
346.     public string Format(string unit, bool toSymbol) =>
347.         toSymbol ? GetSymbol(unit) : unit;
348. 
349.     private static string GetSymbol(string unit) =>
350.         unit switch
351.         {
352.             "Byte" => "B",
353.             "Kilobyte" => "KB",
354.             "Megabyte" => "MB",
355.             "Gigabyte" => "GB",
356.             "Terabyte" => "TB",
357.             "Bit" => "b",
358.             _ => unit
359.         };
360. }
